106	function formatBundledCapabilityPluginLoadError(params: {
107	  pluginId: string;
108	  capabilityLabel: string;
109	  registry: BundledCapabilityRuntimeRegistry;
110	}): Error {
111	  const plugin = params.registry.plugins.find((entry) => entry.id === params.pluginId);
112	  const diagnostics = params.registry.diagnostics
113	    .filter((entry) => entry.pluginId === params.pluginId)
114	    .map((entry) => entry.message);
115	  const detailParts = plugin
116	    ? [
117	        `status=${plugin.status}`,
118	        ...(plugin.error ? [`error=${plugin.error}`] : []),
119	        `providerIds=[${plugin.providerIds.join(", ")}]`,
120	        `webFetchProviderIds=[${plugin.webFetchProviderIds.join(", ")}]`,
121	        `webSearchProviderIds=[${plugin.webSearchProviderIds.join(", ")}]`,
122	      ]
123	    : ["plugin record missing"];
124	  if (diagnostics.length > 0) {
125	    detailParts.push(`diagnostics=${diagnostics.join(" | ")}`);
126	  }
127	  return new Error(
128	    `bundled ${params.capabilityLabel} contract load failed for ${params.pluginId}: ${detailParts.join("; ")}`,
129	  );
130	}
