193	  try {
194	    providerContractLoadError = undefined;
195	    const entries = loadScopedCapabilityRuntimeRegistryEntries({
196	      pluginId,
197	      capabilityLabel: "provider",
198	      loadEntries: (registry) =>
199	        registry.providers
200	          .filter((entry) => entry.pluginId === pluginId)
201	          .map((entry) => ({
202	            pluginId: entry.pluginId,
203	            provider: entry.provider,
204	          })),
