254	function resolveWebSearchCredentialValue(provider: WebSearchProviderPlugin): unknown {
255	  if (provider.requiresCredential === false) {
256	    return `${provider.id}-no-key-needed`;
257	  }
258	  const envVar = provider.envVars.find((entry) => entry.trim().length > 0);
259	  if (!envVar) {
260	    return `${provider.id}-test`;
261	  }
262	  if (envVar === "OPENROUTER_API_KEY") {
263	    return "openrouter-test";
264	  }
265	  return envVar.toLowerCase().includes("api_key") ? `${provider.id}-test` : "sk-test";
266	}
