43	function readJsonFile<T>(filePath: string): T {
44	  return JSON.parse(fs.readFileSync(filePath, "utf8")) as T;
45	}
46	
47	function normalizeText(value: unknown): string | undefined {
48	  if (typeof value !== "string") {
49	    return undefined;
50	  }
51	  const trimmed = value.trim();
52	  return trimmed || undefined;
53	}
54	
55	function readBundledPluginRecords(): BundledPluginRecord[] {
56	  return fs
57	    .readdirSync(EXTENSIONS_ROOT)
58	    .toSorted()
59	    .flatMap((dirName) => {
60	      const rootDir = path.join(EXTENSIONS_ROOT, dirName);
61	      const packagePath = path.join(rootDir, "package.json");
62	      const manifestPath = path.join(rootDir, "openclaw.plugin.json");
63	      if (!fs.existsSync(packagePath) || !fs.existsSync(manifestPath)) {
64	        return [];
65	      }
66	
67	      const manifest = readJsonFile<PluginManifestShape>(manifestPath);
68	      const pkg = readJsonFile<OpenClawPackageShape>(packagePath);
69	      const manifestId = normalizeText(manifest.id);
70	      const packageName = normalizeText(pkg.name);
71	      if (!manifestId || !packageName) {
72	        return [];
73	      }
74	
75	      return [
76	        {
77	          dirName,
78	          packageName,
79	          manifestId,
80	          installNpmSpec: normalizeText(pkg.openclaw?.install?.npmSpec),
81	          channelId: normalizeText(pkg.openclaw?.channel?.id),
82	        },
83	      ];
84	    });
85	}
86	
87	function resolveAllowedPackageNamesForId(pluginId: string): string[] {
88	  return ALLOWED_PACKAGE_SUFFIXES.map((suffix) => `@openclaw/${pluginId}${suffix}`);
89	}
90	
91	function resolveBundledPluginMismatches(
92	  collectMismatches: (records: BundledPluginRecord[]) => string[],
93	) {
94	  return collectMismatches(readBundledPluginRecords());
95	}
