  // Status monitoring
  statusAdapter: createComputedAccountStatusAdapter(...),

  // Configuration
  configAdapter: ircConfigAdapter,
  configSchema: IrcChannelConfigSchema,

  // Setup UI
  setupWizard: ircSetupWizard,
  setupAdapter: ircSetupAdapter,

