  password: string;
  passwordSource: "env" | "passwordFile" | "config" | "none";
  config: IrcAccountConfig; // Full merged config
};

// List all configured accounts
export const listIrcAccountIds = createAccountListHelpers(...);
export const resolveDefaultIrcAccountId = ...;

// Resolve a specific account with merged config
export function resolveIrcAccount(params) { ... }
