```

Identical structure to `extensions/irc/src/runtime.ts`.

---

### `extensions/pulseboard/src/types.ts`

Domain types, importing shared config types from `./runtime-api.js` (keeps types out of core):

```typescript
import type { DmPolicy, GroupPolicy, MarkdownConfig, OpenClawConfig } from "./runtime-api.js";

export type PulseBoardGroupConfig = {
  requireMention?: boolean;
  enabled?: boolean;
  allowFrom?: Array<string | number>;
  systemPrompt?: string;
};

export type PulseBoardAccountConfig = {
  name?: string;
  enabled?: boolean;
  serverUrl?: string;      // PulseBoard server base URL
  username?: string;       // Username on PulseBoard
  token?: string;          // Auth token (plain string; schema uses buildSecretInputSchema)
  dmPolicy?: DmPolicy;
  allowFrom?: Array<string | number>;
  defaultTo?: string;
  groupPolicy?: GroupPolicy;
  boards?: string[];       // Subscribed board names (without ! prefix)
  groups?: Record<string, PulseBoardGroupConfig>;
  markdown?: MarkdownConfig;
};

export type PulseBoardConfig = PulseBoardAccountConfig & {
  accounts?: Record<string, PulseBoardAccountConfig>;
  defaultAccount?: string;
};

// Augments the host OpenClawConfig shape so account resolvers are fully typed
export type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseBoardConfig;
  };
};

export type PulseBoardInboundMessage = {
  messageId: string;
  /** Normalized target: board name (with !) for group posts, sender username for DMs. */
  target: string;
  senderUsername: string;
  text: string;
  timestamp: number;
  isGroup: boolean;
};
```

No `PulseBoardProbe` type is needed unless a real probe is implemented; the status adapter can
use a generic snapshot for the stub.

