```

Only the account helpers need to be on the public barrel (the same minimal scope IRC uses).

---

### `extensions/pulseboard/src/runtime-api.ts`

Because there is no `src/plugin-sdk/pulseboard.ts` core facade (which would require modifying a
core file), this barrel imports directly from individual general `openclaw/plugin-sdk/*` subpaths.
All these subpaths are in `scripts/lib/plugin-sdk-entrypoints.json`.

```typescript
// Internal runtime barrel for the PulseBoard extension.
// Imports from individual plugin-sdk subpaths because no dedicated pulseboard facade exists.

export { getChatChannelMeta } from "openclaw/plugin-sdk/core";
export { DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/account-id";
export { buildBaseChannelStatusSummary } from "openclaw/plugin-sdk/status-helpers";
export { createAccountStatusSink } from "openclaw/plugin-sdk/channel-lifecycle";
export { PAIRING_APPROVED_MESSAGE } from "openclaw/plugin-sdk/channel-status";
export { chunkTextForOutbound } from "openclaw/plugin-sdk/reply-chunking";
