### `extensions/pulseboard/src/send.ts`

Stub send function (no real HTTP call for the fictional platform):

```typescript
import { getPulseBoardRuntime } from "./runtime.js";
import { resolvePulseBoardAccount } from "./accounts.js";
import { normalizePulseBoardMessagingTarget } from "./normalize.js";
import type { CoreConfig } from "./types.js";

export type SendPulseBoardOptions = {
  cfg?: CoreConfig;
  accountId?: string;
  replyTo?: string;
};

export type SendPulseBoardResult = {
  messageId: string;
  target: string;
};

export async function sendMessagePulseboard(
  to: string,
  text: string,
  opts: SendPulseBoardOptions = {},
): Promise<SendPulseBoardResult> {
  const runtime = getPulseBoardRuntime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" ` +
      "(need serverUrl and username in channels.pulseboard).",
    );
  }

  const target = normalizePulseBoardMessagingTarget(to);
  if (!target) throw new Error(`Invalid PulseBoard target: ${to}`);
  if (!text.trim()) throw new Error("Message must be non-empty for PulseBoard sends");

  // Record outbound activity for status tracking
  try {
    runtime.channel.activity.record({
      channel: "pulseboard",
      accountId: account.accountId,
      direction: "outbound",
    });
  } catch {
    // Tolerate missing runtime during tests
  }

  // Stub: generate a deterministic-ish message ID (no real HTTP call)
  const messageId = `pb-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`;
  return { messageId, target };
}
