// PulseBoard target format:
//   !board-name  → group (bulletin board)
//   username     → direct message

const PULSEBOARD_TARGET_PATTERN = /^[^\s]+$/u;

/** Returns true when the target is a board (group) rather than a direct user. */
export function isBoardTarget(target: string): boolean {
  return target.startsWith("!");
}

/**
 * Normalize a raw PulseBoard messaging target string.
 * Supported input forms:
 *   - `!board-name`         (board direct)
 *   - `board:board-name`    (board: prefix, `!` added automatically)
 *   - `user:username`       (user: prefix stripped)
 *   - `pulseboard:!board`   (pulseboard: prefix stripped)
 *   - plain `username`      (direct message)
 */
export function normalizePulseBoardMessagingTarget(raw: string): string | undefined {
  const trimmed = raw.trim();
  if (!trimmed) {
    return undefined;
  }
  let target = trimmed;
  if (target.toLowerCase().startsWith("pulseboard:")) {
    target = target.slice("pulseboard:".length).trim();
  }
  if (target.toLowerCase().startsWith("board:")) {
    target = target.slice("board:".length).trim();
    if (!target.startsWith("!")) {
      target = `!${target}`;
    }
  }
  if (target.toLowerCase().startsWith("user:")) {
    target = target.slice("user:".length).trim();
  }
  if (!target || !looksLikePulseBoardTargetId(target)) {
    return undefined;
  }
  return target;
}

/** Returns true when the string looks like a valid PulseBoard target id. */
export function looksLikePulseBoardTargetId(raw: string): boolean {
  const trimmed = raw.trim();
  if (!trimmed) {
    return false;
  }
  return PULSEBOARD_TARGET_PATTERN.test(trimmed);
}

/** Normalize a raw allowlist entry to a canonical lowercase PulseBoard username. */
export function normalizePulseBoardAllowEntry(raw: string): string {
  let value = raw.trim().toLowerCase();
  if (!value) {
    return "";
  }
  if (value.startsWith("pulseboard:")) {
    value = value.slice("pulseboard:".length);
  }
  if (value.startsWith("user:")) {
    value = value.slice("user:".length);
  }
  return value.trim();
}

/** Check whether a sender is covered by an allowlist. */
export function resolvePulseBoardAllowlistMatch(params: {
  allowFrom: string[];
  senderUsername: string;
}): { allowed: boolean; source?: string } {
  const allowSet = new Set(
    params.allowFrom.map((e) => e.trim().toLowerCase()).filter(Boolean),
  );
  if (allowSet.has("*")) {
    return { allowed: true, source: "wildcard" };
  }
  const username = params.senderUsername.trim().toLowerCase();
  if (username && allowSet.has(username)) {
    return { allowed: true, source: username };
  }
  return { allowed: false };
}

