function readJsonFile(filePath) {
  return JSON.parse(fs.readFileSync(filePath, 'utf8'));
}

function normalizeText(value) {
  if (typeof value !== 'string') return undefined;
  const trimmed = value.trim();
  return trimmed || undefined;
}

function readBundledPluginRecords() {
  return fs.readdirSync(EXTENSIONS_ROOT).toSorted().flatMap((dirName) => {
    const rootDir = path.join(EXTENSIONS_ROOT, dirName);
    const packagePath = path.join(rootDir, 'package.json');
    const manifestPath = path.join(rootDir, 'openclaw.plugin.json');
    if (!fs.existsSync(packagePath) || !fs.existsSync(manifestPath)) return [];
    const manifest = readJsonFile(manifestPath);
    const pkg = readJsonFile(packagePath);
    const manifestId = normalizeText(manifest.id);
    const packageName = normalizeText(pkg.name);
    if (!manifestId || !packageName) return [];
    return [{ dirName, packageName, manifestId, installNpmSpec: normalizeText(pkg.openclaw?.install?.npmSpec), channelId: normalizeText(pkg.openclaw?.channel?.id) }];
  });
}

