console.log('NpmSpec mismatches:', mismatch3.filter(m => m.includes('pulseboard')));

// Check 4: channel.id == manifest id
const mismatch4 = records.filter(({channelId, manifestId}) => typeof channelId === 'string' && channelId !== manifestId).map(({dirName, manifestId, channelId}) => dirName + ': channel=' + channelId + ', id=' + manifestId);
console.log('Channel id mismatches:', mismatch4.filter(m => m.includes('pulseboard')));
